import argparse
import json
import os
import numpy as np
from cogniplan_env import ExplorationEnv
import heapq


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = tuple(np.round(n["coords"], 6))
        coord_to_idx[coord] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(tuple(np.round(nb, 6)))
            else:
                j = int(nb) if 0 <= int(nb) < N else None
            if j is not None and j != i:
                w = float(np.linalg.norm(np.array(n["coords"], dtype=float) - np.array(nodes[j]["coords"], dtype=float)))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        j = coord_to_idx.get(tuple(np.round(nb, 6)))
        if j is None:
            continue
        w = float(np.linalg.norm(np.array(robot_pos, dtype=float) - np.array(nb, dtype=float)))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class Explorer:
    def __init__(self):
        self.target_coord = None
        self.steps_since_replan = 0
        self.step_count = 0
        self.recent_positions = []
        self.max_commit = 8

    def _target_valid(self, nodes, target_coord):
        for n in nodes:
            if np.allclose(n["coords"], target_coord, atol=0.2):
                if n.get("utility", 0) > 0 and not n.get("visited", False):
                    return True
                return False
        return False

    def _get_step(self, adj, coord_to_idx, r_idx, nodes, neighbors, target_coord):
        target_idx = coord_to_idx.get(tuple(np.round(target_coord, 6)))
        if target_idx is None:
            return None
        dist, prev = dijkstra(adj, r_idx)
        if dist[target_idx] == float('inf'):
            return None
        cur = target_idx
        while prev[cur] is not None and prev[cur] != r_idx:
            cur = prev[cur]
        if prev[cur] != r_idx:
            return None
        for nb in neighbors:
            if np.allclose(nb, nodes[cur]["coords"], atol=0.5):
                return tuple(nb)
        # nearest neighbor fallback
        best = min(neighbors, key=lambda nb: np.linalg.norm(np.array(nb) - np.array(nodes[cur]["coords"])))
        return tuple(best)

    def _pick_target(self, nodes, dist, robot_pos, neighbors, frontiers):
        steps_remaining = max(0, 128 - self.step_count)
        best_score = -float('inf')
        best_coord = None
        best_dist = None

        for j, n in enumerate(nodes):
            d = dist[j]
            if d == float('inf'):
                continue
            utility = float(n.get("utility", 0.0))
            if utility <= 0:
                continue
            visited = bool(n.get("visited", False))
            score = utility / (d + 0.5)
            if visited:
                score *= 0.02
            # discourage recently visited areas
            node_pos = np.array(n["coords"])
            for recent in self.recent_positions:
                if np.linalg.norm(node_pos - np.array(recent)) < 4.0:
                    score *= 0.7
            # step budget: avoid very long hauls when running low on steps
            est_steps = d / 3.2
            if est_steps > steps_remaining:
                score *= 0.01
            elif est_steps > steps_remaining * 0.7:
                score *= 0.3
            if score > best_score + 1e-6:
                best_score = score
                best_coord = tuple(n["coords"])
                best_dist = d
            elif abs(score - best_score) <= 1e-6:
                if best_dist is None or d < best_dist:
                    best_coord = tuple(n["coords"])
                    best_dist = d

        # Fallback 1: nearest unvisited node
        if best_coord is None:
            best_d = float('inf')
            for j, n in enumerate(nodes):
                d = dist[j]
                if d == float('inf'):
                    continue
                if not n.get("visited", False) and d < best_d:
                    best_d = d
                    best_coord = tuple(n["coords"])

        # Fallback 2: nearest frontier direction
        if best_coord is None and frontiers:
            farr = np.array(frontiers)
            best_val = float('inf')
            for j, n in enumerate(nodes):
                d = dist[j]
                if d == float('inf'):
                    continue
                fd = np.min(np.linalg.norm(farr - np.array(n["coords"]), axis=1))
                val = d + fd
                if val < best_val:
                    best_val = val
                    best_coord = tuple(n["coords"])

        return best_coord

    def select_target(self, obs):
        robot_pos = np.array(obs["robot_pos"], dtype=np.float32)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        self.step_count += 1
        self.recent_positions.append(tuple(np.round(robot_pos, 2)))
        if len(self.recent_positions) > 12:
            self.recent_positions.pop(0)

        # try to continue committed target
        if self.target_coord is not None and self.steps_since_replan < self.max_commit:
            if self._target_valid(nodes, self.target_coord):
                adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
                step = self._get_step(adj, coord_to_idx, r_idx, nodes, neighbors, self.target_coord)
                if step is not None:
                    self.steps_since_replan += 1
                    return step

        # replan
        self.steps_since_replan = 0
        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, _ = dijkstra(adj, r_idx)
        self.target_coord = self._pick_target(nodes, dist, robot_pos, neighbors, frontiers)
        if self.target_coord is None:
            return tuple(neighbors[0])
        step = self._get_step(adj, coord_to_idx, r_idx, nodes, neighbors, self.target_coord)
        if step is None:
            return tuple(neighbors[0])
        self.steps_since_replan = 1
        return step


def run_episode(env):
    planner = Explorer()
    obs = env.reset()
    for step in range(128):
        target = planner.select_target(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done", False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        import torch
        _ = torch.load(ckpt_path, map_location="cpu")

    eval_config_path = os.path.join(args.data_path, "eval_config.json")
    with open(eval_config_path, "r") as f:
        eval_config = json.load(f)

    maps = []
    maps_dir = os.path.join(args.data_path, "maps_eval")
    for env_type in ["room", "tunnel", "outdoor"]:
        type_dir = os.path.join(maps_dir, env_type)
        if not os.path.isdir(type_dir):
            continue
        for fname in sorted(os.listdir(type_dir)):
            if fname.lower().endswith(".png"):
                maps.append((env_type, os.path.join(type_dir, fname)))

    per_episode = []
    per_type = {t: {"explored_rate": [], "travel_distance": [], "success": []} for t in ["room", "tunnel", "outdoor"]}

    for env_type, map_path in maps:
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env)
        success = 1 if metrics.get("success", False) else 0
        explored_rate = float(metrics.get("explored_rate", 0.0))
        travel_distance = float(metrics.get("travel_distance", 0.0))
        rel_path = os.path.relpath(map_path, args.data_path)
        per_episode.append({
            "map_path": rel_path,
            "env_type": env_type,
            "success": success,
            "travel_distance": travel_distance,
            "explored_rate": explored_rate
        })
        per_type[env_type]["explored_rate"].append(explored_rate)
        per_type[env_type]["travel_distance"].append(travel_distance)
        per_type[env_type]["success"].append(success)

    # aggregate
    total_success = sum(e["success"] for e in per_episode)
    total_episodes = len(per_episode)
    success_rate = total_success / total_episodes if total_episodes else 0.0
    explored_rate = float(np.mean([e["explored_rate"] for e in per_episode])) if per_episode else 0.0
    successful_distances = [e["travel_distance"] for e in per_episode if e["success"] == 1]
    travel_distance = float(np.mean(successful_distances)) if successful_distances else 0.0

    per_type_out = {}
    for t in ["room", "tunnel", "outdoor"]:
        s = sum(per_type[t]["success"])
        n = len(per_type[t]["success"])
        d = [x for x, su in zip(per_type[t]["travel_distance"], per_type[t]["success"]) if su == 1]
        per_type_out[t] = {
            "explored_rate": float(np.mean(per_type[t]["explored_rate"])) if per_type[t]["explored_rate"] else 0.0,
            "travel_distance": float(np.mean(d)) if d else 0.0,
            "success_rate": s / n if n else 0.0,
        }

    result = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type_out,
        "total_episodes": total_episodes,
    }

    os.makedirs(os.path.dirname(args.output) or ".", exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(result, f, indent=2)


if __name__ == "__main__":
    main()
